import { Component, OnInit } from '@angular/core';
import { EstoqueService } from '../../services/estoque.service';
import { Produto } from '../../models';

@Component({
  selector: 'app-produtos',
  templateUrl: './produtos.component.html',
  styleUrls: ['./produtos.component.css']
})
export class ProdutosComponent implements OnInit {
  produtos: Produto[] = [];
  loading = false;
  error = '';
  showForm = false;
  editingId: number | null = null;

  filtroCodigo: string = '';
  filtroDescricao: string = '';
  filtroSaldo: string = '';

  form = {
    codigo: 0,
    descricao: '',
    saldo: 0
  };

  constructor(private estoqueService: EstoqueService) { }

  ngOnInit(): void {
    this.carregarProdutos();
  }

  carregarProdutos(): void {
    this.loading = true;
    this.error = '';
    this.estoqueService.obterTodosProdutos().subscribe({
      next: (data) => {
        this.produtos = data;
        this.loading = false;
      },
      error: (err) => {
        this.error = 'Erro ao carregar produtos: ' + (err.message || 'Erro desconhecido');
        this.loading = false;
      }
    });
  }

  abrirFormulario(): void {
    this.showForm = true;
    this.editingId = null;
    this.form = { codigo: 0, descricao: '', saldo: 0 };
  }

  fecharFormulario(): void {
    this.showForm = false;
    this.form = { codigo: 0, descricao: '', saldo: 0 };
  }

  salvarProduto(): void {
    if (!this.form.descricao.trim()) {
      this.error = 'Descrição é obrigatória';
      return;
    }

    this.loading = true;
    this.error = '';

    const request = {
      codigo: this.form.codigo,
      descricao: this.form.descricao,
      saldo: this.form.saldo
    };

    if (this.editingId) {
      this.estoqueService.atualizarProduto(this.editingId, request).subscribe({
        next: () => {
          this.carregarProdutos();
          this.fecharFormulario();
        },
        error: (err) => {
          this.error = 'Erro ao atualizar produto: ' + (err.message || 'Erro desconhecido');
          this.loading = false;
        }
      });
    } else {
      this.estoqueService.criarProduto(request).subscribe({
        next: () => {
          this.carregarProdutos();
          this.fecharFormulario();
        },
        error: (err) => {
          this.error = 'Erro ao criar produto: ' + (err.message || 'Erro desconhecido');
          this.loading = false;
        }
      });
    }
  }

  editarProduto(produto: Produto): void {
    this.editingId = produto.id;
    this.form = { ...produto };
    this.showForm = true;
  }

  deletarProduto(id: number): void {
    if (!confirm('Tem certeza que deseja deletar este produto?')) {
      return;
    }

    this.loading = true;
    this.error = '';
    this.estoqueService.deletarProduto(id).subscribe({
      next: () => {
        this.carregarProdutos();
      },
      error: (err) => {
        this.error = 'Erro ao deletar produto: ' + (err.message || 'Erro desconhecido');
        this.loading = false;
      }
    });
  }

  get produtosFiltrados(): Produto[] {
    let filtrados = this.produtos;

    if (this.filtroCodigo) {
      filtrados = filtrados.filter(p =>
        p.codigo.toString().includes(this.filtroCodigo)
      );
    }

    if (this.filtroDescricao) {
      filtrados = filtrados.filter(p =>
        p.descricao.toLowerCase().includes(this.filtroDescricao.toLowerCase())
      );
    }

    if (this.filtroSaldo) {
      const saldoMin = parseInt(this.filtroSaldo);
      filtrados = filtrados.filter(p => p.saldo <= saldoMin);
    }

    return filtrados;
  }

  limparFiltros(): void {
    this.filtroCodigo = '';
    this.filtroDescricao = '';
    this.filtroSaldo = '';
  }
}
<div class="container">
  <h1>Gestão de Produtos</h1>

  <div *ngIf="error" class="error-message">
    {{ error }}
  </div>

  <div *ngIf="loading" class="spinner">
    Carregando...
  </div>

  <button (click)="abrirFormulario()" class="btn btn-primary" *ngIf="!showForm">
    + Novo Produto
  </button>

  <div *ngIf="showForm" class="form-container">
    <h2>{{ editingId ? 'Editar' : 'Novo' }} Produto</h2>
    <div class="form-group">
      <label>Código:</label>
      <input type="number" [(ngModel)]="form.codigo" class="form-input" />
    </div>
    <div class="form-group">
      <label>Descrição:</label>
      <input type="text" [(ngModel)]="form.descricao" class="form-input" />
    </div>
    <div class="form-group">
      <label>Saldo:</label>
      <input type="number" [(ngModel)]="form.saldo" class="form-input" />
    </div>
    <div class="form-buttons">
      <button (click)="salvarProduto()" class="btn btn-success">Salvar</button>
      <button (click)="fecharFormulario()" class="btn btn-secondary">Cancelar</button>
    </div>
  </div>

  <div *ngIf="!showForm && !loading && produtos.length > 0" class="table-container">
    <!-- Filtros de Busca -->
    <div class="filters-container">
      <div class="filter-group">
        <label>🔍 Código:</label>
        <input 
          type="text" 
          [(ngModel)]="filtroCodigo" 
          placeholder="Buscar por código"
          class="filter-input">
      </div>

      <div class="filter-group">
        <label>Descrição:</label>
        <input 
          type="text" 
          [(ngModel)]="filtroDescricao" 
          placeholder="Buscar por descrição"
          class="filter-input">
      </div>

      <div class="filter-group">
        <label>Saldo ≤:</label>
        <input 
          type="number" 
          [(ngModel)]="filtroSaldo" 
          placeholder="Saldo máximo"
          class="filter-input">
      </div>

      <button (click)="limparFiltros()" class="btn btn-secondary" *ngIf="filtroCodigo || filtroDescricao || filtroSaldo">
        ✖️ Limpar
      </button>
    </div>

    <table class="table">
      <thead>
        <tr>
          <th>ID</th>
          <th>Código</th>
          <th>Descrição</th>
          <th>Saldo</th>
          <th>Ações</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let produto of produtosFiltrados" [class.low-stock]="produto.saldo < 5">
          <td>{{ produto.id }}</td>
          <td>{{ produto.codigo }}</td>
          <td>{{ produto.descricao }}</td>
          <td>{{ produto.saldo }}</td>
          <td>
            <button (click)="editarProduto(produto)" class="btn btn-small btn-info">Editar</button>
            <button (click)="deletarProduto(produto.id)" class="btn btn-small btn-danger">Deletar</button>
          </td>
        </tr>
      </tbody>
    </table>
  </div>

  <div *ngIf="!showForm && !loading && produtos.length === 0" class="empty-message">
    Nenhum produto cadastrado.
  </div>
</div>
